  "trip": {
    "destination": "Moscow",
    "duration_days": 3,
    "itinerary": [
      {
        "day": 1,
        "title": "Historical Landmarks",
        "schedule": [
          {
            "time": "Morning",
            "activity": "Explore Red Square, including St. Basil's Cathedral and Lenin's Mausoleum."
          },
          {
            "time": "Afternoon",
            "activity": "Tour the Moscow Kremlin, visiting the Armoury Chamber and Cathedral Square."
          },
          {
            "time": "Evening",
            "activity": "Walk through Zaryadye Park and enjoy dinner near the Moskva River."
          }
        ]
      },
      {
        "day": 2,
        "title": "Art and Culture",
        "schedule": [
          {
            "time": "Morning",
            "activity": "Visit the State Tretyakov Gallery to see masterpieces of Russian fine art."
          },
          {
            "time": "Afternoon",
            "activity": "Stroll down Arbat Street for souvenirs, street performances, and local cafes."
          },
          {
            "time": "Evening",
            "activity": "Attend a ballet or opera performance at the world-renowned Bolshoi Theatre."
          }
        ]
      },
      {
        "day": 3,
        "title": "Soviet Space and Grand Views",
        "schedule": [
          {
            "time": "Morning",
            "activity": "Discover space exploration history at the Museum of Cosmonautics."
          },
          {
